mapper.select:
SELECT s.id, s.student_no, u.name, s.class_id, c.name AS class_name, c.major_id, m.name AS major_name, m.department_id, d.name AS department_name, s.admission_date, s.graduation_date, s.gender, CASE s.gender WHEN 0 THEN '男' WHEN 1 THEN '女' ELSE '未知' END AS gender_desc, s.id_card, s.birthday, s.address, s.status, CASE s.status WHEN 0 THEN '在读' WHEN 1 THEN '毕业' WHEN 2 THEN '休学' WHEN 3 THEN '退学' ELSE '未知' END AS status_desc, u.email, u.phone, s.create_time FROM student s LEFT JOIN sys_user u ON s.user_id = u.id LEFT JOIN class c ON s.class_id = c.id LEFT JOIN major m ON c.major_id = m.id LEFT JOIN department d ON m.department_id = d.id WHERE 1 = 1
AND s.student_no LIKE CONCAT('%', #{studentNo}, '%')
AND u.name LIKE CONCAT('%', #{name}, '%')
AND s.class_id = #{classId}
AND s.gender = #{gender}
AND c.major_id = #{majorId}
AND m.department_id = #{departmentId}
AND u.phone LIKE CONCAT('%', #{phone}, '%')
AND s.status = #{status}
AND s.admission_date >= #{startDate}
AND s.admission_date <= #{endDate}
ORDER BY s.id DESC

SELECT cs.id, c.id AS course_id, c.name AS course_name, c.code AS course_code, c.credit, c.hours, c.type AS course_type, co.id AS course_offering_id, co.teacher_id, t_user.name AS teacher_name, co.semester, co.class_time, co.location, cs.selection_time, cs.score, cs.status FROM course_selection cs JOIN course_offering co ON cs.course_offering_id = co.id JOIN course c ON co.course_id = c.id JOIN teacher t ON co.teacher_id = t.id JOIN sys_user t_user ON t.user_id = t_user.id WHERE cs.student_id = #{studentId}
AND cs.status = #{status}
ORDER BY co.semester DESC, c.id

SELECT cs.id, c.id AS course_id, c.name AS course_name, c.code AS course_code, c.credit, c.hours, c.type AS course_type, t_user.name AS teacher_name, co.semester, cs.score FROM course_selection cs JOIN course_offering co ON cs.course_offering_id = co.id JOIN course c ON co.course_id = c.id JOIN teacher t ON co.teacher_id = t.id JOIN sys_user t_user ON t.user_id = t_user.id WHERE cs.student_id = #{studentId} AND cs.score IS NOT NULL
AND co.semester = #{semester}
ORDER BY co.semester DESC, c.id

SELECT cs.id, c.id AS course_id, c.name AS course_name, c.code AS course_code, c.credit, c.hours, c.type AS course_type, co.id AS course_offering_id, co.teacher_id, t_user.name AS teacher_name, co.semester, co.class_time, co.location, cs.selection_time, cs.score, cs.status FROM course_selection cs JOIN student s ON cs.student_id = s.id JOIN course_offering co ON cs.course_offering_id = co.id JOIN course c ON co.course_id = c.id JOIN teacher t ON co.teacher_id = t.id JOIN sys_user t_user ON t.user_id = t_user.id WHERE s.user_id = #{userId}
AND c.name LIKE CONCAT('%', #{courseName}, '%')
AND c.code LIKE CONCAT('%', #{courseCode}, '%')
AND co.semester = #{semester}
ORDER BY co.semester DESC, c.id

SELECT d.name AS departmentName, COUNT(s.id) AS studentCount FROM student s JOIN class c ON s.class_id = c.id JOIN major m ON c.major_id = m.id JOIN department d ON m.department_id = d.id
YEAR(s.create_time) = #{year}
GROUP BY d.id, d.name ORDER BY studentCount DESC
